(window.webpackJsonp=window.webpackJsonp||[]).push([[68],{540:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\n3D 场景中的设备交互是数字孪生项目的核心体验。本文深入介绍 Three.js Raycaster 的使用技巧，包括射线检测优化、设备高亮效果实现、信息面板联动、以及多层级模型的点击穿透处理，打造流畅的 3D 交互体验。\n&lt;/div&gt;</p>\n<h2>一、Raycaster 基础</h2>\n<p>Raycaster 通过发射一条从相机到鼠标位置的射线，检测与场景中物体的交点：</p>\n<pre><code class=\"language-javascript\">const raycaster = new THREE.Raycaster()\nconst mouse = new THREE.Vector2()\nconst clickableObjects = [] // 可点击的设备网格列表\n\nfunction onMouseClick(event) {\n  // 标准化鼠标坐标\n  const rect = renderer.domElement.getBoundingClientRect()\n  mouse.x = ((event.clientX - rect.left) / rect.width) * 2 - 1\n  mouse.y = -((event.clientY - rect.top) / rect.height) * 2 + 1\n\n  raycaster.setFromCamera(mouse, camera)\n  const intersects = raycaster.intersectObjects(clickableObjects, true)\n\n  if (intersects.length &gt; 0) {\n    handleDeviceClick(intersects[0])\n  }\n}\n\nrenderer.domElement.addEventListener('click', onMouseClick)\n</code></pre>\n<h2>二、性能优化：减少检测对象</h2>\n<p>在包含数百个 Mesh 的场景中，每次射线检测都遍历所有对象会影响性能：</p>\n<h3>1. 分组检测</h3>\n<pre><code class=\"language-javascript\">// 只检测设备层的物体，忽略地板、墙壁等\nconst deviceGroup = new THREE.Group()\ndeviceGroup.name = 'devices'\nscene.add(deviceGroup)\n\n// 加载设备模型时添加到设备组\ndeviceGroup.add(serverMesh)\n\n// 检测时只传入设备组的子对象\nconst intersects = raycaster.intersectObjects(deviceGroup.children, true)\n</code></pre>\n<h3>2. BVH 加速</h3>\n<pre><code class=\"language-javascript\">import { computeBoundsTree, disposeBoundsTree, acceleratedRaycast }\n  from 'three-mesh-bvh'\n\n// 扩展 Three.js 原型\nTHREE.BufferGeometry.prototype.computeBoundsTree = computeBoundsTree\nTHREE.BufferGeometry.prototype.disposeBoundsTree = disposeBoundsTree\nTHREE.Mesh.prototype.raycast = acceleratedRaycast\n\n// 为设备模型构建 BVH\ndeviceMeshes.forEach((mesh) =&gt; {\n  mesh.geometry.computeBoundsTree()\n})\n</code></pre>\n<h3>3. 节流处理</h3>\n<pre><code class=\"language-javascript\">// 鼠标移动事件使用节流\nlet throttleTimer = null\n\nfunction onMouseMove(event) {\n  if (throttleTimer) return\n  throttleTimer = setTimeout(() =&gt; {\n    throttleTimer = null\n    handleHover(event)\n  }, 50) // 50ms 节流\n}\n</code></pre>\n<h2>三、设备高亮效果</h2>\n<h3>边缘发光（OutlinePass）</h3>\n<pre><code class=\"language-javascript\">import { EffectComposer } from 'three/examples/jsm/postprocessing/EffectComposer'\nimport { RenderPass } from 'three/examples/jsm/postprocessing/RenderPass'\nimport { OutlinePass } from 'three/examples/jsm/postprocessing/OutlinePass'\n\nconst composer = new EffectComposer(renderer)\ncomposer.addPass(new RenderPass(scene, camera))\n\nconst outlinePass = new OutlinePass(\n  new THREE.Vector2(window.innerWidth, window.innerHeight),\n  scene,\n  camera\n)\noutlinePass.edgeStrength = 3\noutlinePass.edgeGlow = 1\noutlinePass.edgeThickness = 2\noutlinePass.pulsePeriod = 2\noutlinePass.visibleEdgeColor.set('#00aaff')\ncomposer.addPass(outlinePass)\n\n// 高亮选中设备\nfunction highlightDevice(mesh) {\n  outlinePass.selectedObjects = [mesh]\n}\n\nfunction clearHighlight() {\n  outlinePass.selectedObjects = []\n}\n</code></pre>\n<h3>材质替换高亮</h3>\n<p>对于性能要求更高的场景，使用材质替换代替后处理：</p>\n<pre><code class=\"language-javascript\">const highlightMaterial = new THREE.MeshStandardMaterial({\n  color: 0x0088ff,\n  emissive: 0x0044ff,\n  emissiveIntensity: 0.3,\n  transparent: true,\n  opacity: 0.9\n})\n\nfunction highlightByMaterial(mesh) {\n  // 保存原始材质\n  mesh.userData.originalMaterial = mesh.material\n  mesh.material = highlightMaterial\n}\n\nfunction restoreMaterial(mesh) {\n  if (mesh.userData.originalMaterial) {\n    mesh.material = mesh.userData.originalMaterial\n  }\n}\n</code></pre>\n<h2>四、多层级模型点击穿透</h2>\n<p>GLTF 模型通常有多层嵌套，点击可能命中子 Mesh 而非整个设备：</p>\n<pre><code class=\"language-javascript\">function findRootDevice(object) {\n  let current = object\n  while (current) {\n    // 查找带有设备标识的父节点\n    if (current.userData &amp;&amp; current.userData.deviceId) {\n      return current\n    }\n    current = current.parent\n  }\n  return null\n}\n\nfunction handleDeviceClick(intersect) {\n  const clickedMesh = intersect.object\n  const device = findRootDevice(clickedMesh)\n\n  if (!device) return\n\n  // 高亮整个设备（包括所有子Mesh）\n  device.traverse((child) =&gt; {\n    if (child.isMesh) {\n      highlightByMaterial(child)\n    }\n  })\n\n  // 显示信息面板\n  emit('deviceSelected', {\n    id: device.userData.deviceId,\n    name: device.userData.deviceName,\n    position: device.position.clone(),\n    intersectPoint: intersect.point.clone()\n  })\n}\n</code></pre>\n<h2>五、信息面板联动</h2>\n<pre><code class=\"language-vue\">&lt;template&gt;\n  &lt;transition name=&quot;slide-right&quot;&gt;\n    &lt;div v-if=&quot;selectedDevice&quot; class=&quot;device-panel&quot;&gt;\n      &lt;div class=&quot;panel-header&quot;&gt;\n        &lt;h3&gt;{{ selectedDevice.name }}&lt;/h3&gt;\n        &lt;button @click=&quot;closePanel&quot;&gt;×&lt;/button&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;panel-body&quot;&gt;\n        &lt;div class=&quot;info-item&quot;&gt;\n          &lt;label&gt;设备编号&lt;/label&gt;\n          &lt;span&gt;{{ selectedDevice.id }}&lt;/span&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;info-item&quot;&gt;\n          &lt;label&gt;运行状态&lt;/label&gt;\n          &lt;a-tag :color=&quot;statusColor&quot;&gt;{{ selectedDevice.status }}&lt;/a-tag&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;info-item&quot;&gt;\n          &lt;label&gt;CPU 使用率&lt;/label&gt;\n          &lt;a-progress :percent=&quot;selectedDevice.cpu&quot; size=&quot;small&quot; /&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;info-item&quot;&gt;\n          &lt;label&gt;内存使用率&lt;/label&gt;\n          &lt;a-progress :percent=&quot;selectedDevice.memory&quot; size=&quot;small&quot; /&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;chart-area&quot;&gt;\n          &lt;div ref=&quot;trendChartRef&quot; class=&quot;trend-chart&quot;&gt;&lt;/div&gt;\n        &lt;/div&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n  &lt;/transition&gt;\n&lt;/template&gt;\n</code></pre>\n<h2>六、悬浮 Tooltip</h2>\n<p>鼠标悬浮在设备上时显示简要信息：</p>\n<pre><code class=\"language-javascript\">const tooltip = document.createElement('div')\ntooltip.className = 'three-tooltip'\ndocument.body.appendChild(tooltip)\n\nfunction onMouseMove(event) {\n  const intersect = performRaycast(event)\n\n  if (intersect) {\n    const device = findRootDevice(intersect.object)\n    if (device) {\n      tooltip.innerHTML = `\n        &lt;strong&gt;${device.userData.deviceName}&lt;/strong&gt;\n        &lt;br/&gt;状态: ${device.userData.status}\n      `\n      tooltip.style.display = 'block'\n      tooltip.style.left = event.clientX + 15 + 'px'\n      tooltip.style.top = event.clientY + 15 + 'px'\n\n      // 悬浮高亮\n      document.body.style.cursor = 'pointer'\n      return\n    }\n  }\n\n  tooltip.style.display = 'none'\n  document.body.style.cursor = 'default'\n}\n</code></pre>\n<h2>七、总结</h2>\n<p>完善的 3D 交互系统需要覆盖：</p>\n<ul>\n<li><strong>点击选中</strong>：Raycaster + 多层级穿透处理</li>\n<li><strong>悬浮高亮</strong>：OutlinePass 或材质替换</li>\n<li><strong>信息面板</strong>：Vue 组件与 3D 事件联动</li>\n<li><strong>Tooltip</strong>：鼠标跟随的轻量提示</li>\n<li><strong>性能优化</strong>：分组检测 + BVH 加速 + 节流</li>\n</ul>\n<p>这些交互细节组合在一起，才能构建出真正好用的 3D 可视化应用。</p>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);